import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String directory = "/path/to/files/";

        // Validate user input to prevent directory traversal
        String normalizedInput = Paths.get(userInput).normalize().toString();
        if (!normalizedInput.equals(userInput)) {
            System.out.println("Invalid path specified.");
            return;
        }

        String filePath = Paths.get(directory, userInput).toString();

        try {
            File file = new File(filePath);
            FileInputStream fis = new FileInputStream(file);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

